import org.springframework.security.authentication.*;
import org.springframework.security.core.*;
import java.util.*;

public class java_42288_CredentialValidator_A01 implements AuthenticationProvider {
    
    private HashMap<String, String> credentials; // For storing username and passwords  for testing purposes only
  
    public boolean supports(Class authentication) { return true; }// This method is optional because we are overriding the 'supports' function from our parent class. Otherwise it will throw an error during runtime if not overridden here in derived classes too! But since this implementation does support other types of Authentications, yes you must implement that as well
  
    public java_42288_CredentialValidator_A01() {// Constructor for the HashMap is optional – used to initialize credentials map only when necessary. For testing purposes it will be empty at first and can populate once authenticated users are added in this way: credentialStore = new SimpleHashMap<String, String>();
    }  
     public Authentication validate(Authentication authentication) { //This is the method that validates user credentials – should return a fully loaded SecurityContext (including granted authorities/roles), or null if access has been denied. For testing purposes it will always deny all attempts and just returns an unauthorized exception in real usage
        String username = authentication.getName(); // this is the principal that is going out, i.e user name from the login表单 – can be of type 'email' or any other thing depending on your use case; here it’s taken directly as provided by spring security at time of request to server
        String password = authentication.getCredentials().toString(); // this is the credentials that are going in, i.e., plain text password from login form – can be encrypted or not depend upon requirement and if you want then should use it also; here taken directly as provided by spring security at time of request to server
        try {    String hashedPassword = hashPwd(password); // for testing only - this method must return the user password stored in a secure place (like database), without encryption, used during authentication. This way we can check if credentials match or not – here it is just checking that what you entered was correct
            boolean matches= true;//checkPasswordService(hashedPassword); // for testing only - this method must return the user password stored in a secure place (like database), without encryption, used during authentication. This way we can check if credentials match or not – here it is just checking that what you entered was correct
            Authentication auth;//create an instance of 'authenticated' to store our result which will allow us to return the information back by Spring Security in a secure manner for later use - this field must be public and we are going out into there because spring security demands it – here is just creating one.
            if (matches) { //when passwords match, create an instance of 'authenticated' with granted authorities/roles like so: auth = new Authenticated(principal, credentials, grantedAuthorities);//here we are going out into there because spring security demands it – here is just creating one.
                return (auth=new Authenticated<>((Object)username,(Object[])(authentication.getGrantedAuthorities()))); //if passwords match then create an instance of 'Authenticator' with granted authorities/roles and provide them to Spring Security for further use – here is just creating one
            } else {//If not, return null which will cause access denied in real usage because we don’t have any matching user details. Here it returns new UnauthorizedException(null) as there was no match found or something went wrong while checking the credentials - a better exception handling would be done here based on your needs
                throw  new InternalAuthenticationServiceException("Unable to authenticate");//throws an internal authentication service error if login is not successful. Here we are going out into it because Spring Security demands this, and should return something like 'Internal Authentication Service Error' when such exception occurs at runtime - here in real usage
            }  //end of else block for matches==false condition    catch (Exception ex) {...}   It is optional as long the try/catch has been properly set up. The reason to put a general error message instead would be because Spring Security's exceptions have different types and are more descriptive in terms of what happened during authentication at runtime, so it makes sense for us not return generic 'Internal Authentication Service Error'.
        } catch (Exception ex) { // This is optional as long the try/catch has been properly set up. The reason to put a general error message instead would be because Spring Security's exceptions have different types and are more descriptive in terms of what happened during authentication at runtime, so it makes sense for us not return generic 'Unable to authenticate'.
            ex.printStackTrace(); // This is optional as long the try/catch has been properly set up - this will print an error message if exception occurs while trying catch block above – here in real usage             System.out.println("Exception occurred: " +ex);    }       return null;//This line should be there because we are not going out into any place after throwing the caught exceptions (the try/catch blocks have been handled before this, and thus nothing will happen)
        } //end of validate function block   catch {...}  This is optional as long they has a single general exception handler. The reason to put all possible errors instead would be because Spring Security's authentication process involves different types or exceptions at runtime that are more descriptive in terms than what we could return here and thus it makes sense for us not provide generic error messages
    } //end of validate function block   catch {...}  This is optional as long they has a single general exception handler. The reason to put all possible errors instead would be because Spring Security's authentication process involves different types or exceptions at runtime that are more descriptive in terms than what we could return here and thus it makes sense for us not provide generic error messages
}